{
  "name": "@mcp/rhelp",
  "version": "1.0.0",
  "description": "MCP server for extracting R help pages",
  "main": "index.js",
  "type": "module",
  "bin": {
    "mcp-rhelp": "./index.js"
  },
  "scripts": {
    "start": "node index.js",
    "postinstall": "node setup.js",
    "test": "npm run test:r && npm run test:summary",
    "test:r": "Rscript test/test-r-functions.R",
    "test:mcp": "node test/test-mcp-server.js",
    "test:summary": "node test/test-summary.js",
    "test:basic": "node test/test-basic.js"
  },
  "dependencies": {
    "@modelcontextprotocol/sdk": "^1.0.4"
  },
  "engines": {
    "node": ">=18"
  },
  "preferGlobal": true,
  "repository": {
    "type": "git",
    "url": "https://github.com/yourusername/mcp-rhelp.git"
  },
  "keywords": ["mcp", "r", "help", "documentation"],
  "author": "",
  "license": "MIT"
}
